sp_css.css:
/*
Use this stylesheet for the widget Tasker Modal - Delete Task.
The widget will find the CSS in a auto filled <style> tag.

2.7.0 | 2021-08-29 | mmcc | STRY0107404 - Draft Scheduled Tasks – UI – Delete Modal 
Put into a style sheet
2.7.0 | 2021-09-03 | mmcc | DFCT0010476 - "Acknowledgement Prompt" does not have an "Acknowledge" button so users cannot use Tasker
  Dropped class modal-footer; Added class .dtech-modal-widget-body
  Change class dtech-modal-footer to dtech-modal-widget-footer and updated to have padding-top to reduce white space and position since body sets it as well
*/

.dtech-box {
  display: flex;
}

/* Must be a descendant of the class dtech-box */
.dtech-box .dtech-push-right {
  margin-left: auto!important;
}

/* this was a copy of Bootstrap's modal-body */
.dtech-modal-widget-body {
  padding: 15px;
  position: relative;
}

/* this was a copy of Bootstrap's modal-footer */
.dtech-modal-widget-footer {
  /* padding: 15px; */
  padding-top: 15px;
  text-align: right;
  border-top: 1px solid #e5e5e5;
  /* added position */
  position: relative;
}

.dtech-text-center {
  text-align: center;
}

h1 {
  color: $tasker-color-brown-red;
}

.dtech-infoRound28-warn {
  color: $tasker-warning64-fill;
  height: 60px;
  width: 60px;
}

.dtech-max-width-fit-content {
  max-width: fit-content;
}

.dtech-task-name {
  color: $tasker-delete-prompt-task-name;
  margin-bottom: 25px;
}

.dtech-perm-delete {
  color: $tasker-delete-prompt-perm-delete;
}

.dtech-subtasks-also-deleted {
  color: $tasker-delete-prompt-subtasks-also-deleted;
  margin-left: 5px;
}
